bash_commands.command:
python3 << 'EOF'
import py_compile
import os

errors = []
files_checked = 0

for root, dirs, files in os.walk('/workspace/numpy'):
    if '__pycache__' in root:
        continue

    for file in files:
        if file.endswith('.py'):
            filepath = os.path.join(root, file)
            files_checked += 1
            try:
                py_compile.compile(filepath, doraise=True)
                print(f"✓ {filepath}")
            except py_compile.PyCompileError as e:
                errors.append((filepath, str(e)))
                print(f"✗ {filepath}")

print(f"\n{'='*60}")
print(f"Syntax Check Results:")
print(f"Files checked: {files_checked}")
print(f"Errors found: {len(errors)}")

if errors:
    print(f"\nErrors:")
    for filepath, error in errors:
        print(f"\n{filepath}:")
        print(f"  {error}")
else:
    print("\n✓ All files have valid Python syntax!")
EOF

